import{_ as e,o as t,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Creating Training Plans","description":"","frontmatter":{},"headers":[],"relativePath":"training/creating-plans.md","filePath":"training/creating-plans.md"}'),n={name:"training/creating-plans.md"};function l(o,a,s,d,c,h){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="creating-training-plans" tabindex="-1">Creating Training Plans <a class="header-anchor" href="#creating-training-plans" aria-label="Permalink to &quot;Creating Training Plans&quot;">​</a></h1><p>Training plans are the formal record of development work for a player. They connect a specific development priority to drill resources and track progress over time.</p><h2 id="creating-from-a-suggestion" tabindex="-1">Creating from a Suggestion <a class="header-anchor" href="#creating-from-a-suggestion" aria-label="Permalink to &quot;Creating from a Suggestion&quot;">​</a></h2><p>The fastest way to create a training plan is from a suggestion card:</p><ol><li>Find the suggestion in the player&#39;s Training section or the team Training dashboard</li><li>Tap <strong>Create Training Plan</strong></li><li>The plan pre-fills with the player, area, and suggested focus</li><li>Add your own notes and specific objectives</li><li>Tap <strong>Save</strong></li></ol><h2 id="creating-manually" tabindex="-1">Creating Manually <a class="header-anchor" href="#creating-manually" aria-label="Permalink to &quot;Creating Manually&quot;">​</a></h2><ol><li>Navigate to <strong>Training Plans</strong></li><li>Tap <strong>+ New Plan</strong></li><li>Select the player</li><li>Select the training area (Pitching, Hitting, Fielding, Baserunning, Mechanics)</li><li>Enter the training focus — describe what specifically needs work</li><li>Add notes, drills, and objectives</li><li>Tap <strong>Save</strong></li></ol><h2 id="plan-fields" tabindex="-1">Plan Fields <a class="header-anchor" href="#plan-fields" aria-label="Permalink to &quot;Plan Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Player</td><td>The player this plan is for</td></tr><tr><td>Area</td><td>Which area of the game</td></tr><tr><td>Focus</td><td>Specific skill or mechanic being addressed</td></tr><tr><td>Notes</td><td>Coach notes on approach and context</td></tr><tr><td>Target metric</td><td>The stat or score you want to improve</td></tr><tr><td>Target value</td><td>The goal — e.g. &quot;BA above .250&quot; or &quot;Strike rate above 60%&quot;</td></tr><tr><td>Drills</td><td>Notes on specific drills or YouTube searches used</td></tr></tbody></table><h2 id="active-vs-archived-plans" tabindex="-1">Active vs Archived Plans <a class="header-anchor" href="#active-vs-archived-plans" aria-label="Permalink to &quot;Active vs Archived Plans&quot;">​</a></h2><p>Plans remain <strong>Active</strong> until you archive them. Archive a plan when:</p><ul><li>The underlying metric has improved past threshold</li><li>The focus area has changed</li><li>The season is over</li></ul><p>Archived plans remain in the player&#39;s history and can be referenced in report cards.</p>',13)])])}const u=e(n,[["render",l]]);export{p as __pageData,u as default};
